const input = $input.first().json;
const body = input.body || input;

const isPdf = body.input_method === 'pdf';

if (isPdf) {
  if (!body.pdf_text || body.pdf_text.trim() === '') {
    throw new Error('PDF text is empty — failed to parse PDF content');
  }
} else {
  const required = [
    'entity',
    'key_activities', 'needs', 'value_propositions', 'channels',
    'target_audience', 'kpis', 'strategic_context',
    'budget_indication', 'follow_up_by'
  ];
  const missing = required.filter(k => !body[k] || body[k].trim() === '');
  if (missing.length > 0) throw new Error(`Required fields cannot be empty: ${missing.join(', ')}`);
}

const cleanedInput = {
  input_method: body.input_method || 'text',

  // Campaign Info
  entity:             body.entity?.trim() || '-',
  date:               body.date?.trim() || '-',
  contact_person:     body.contact_person?.trim() || '-',
  completed_by:       body.completed_by?.trim() || '-',

  // BMC Fields
  key_activities:     body.key_activities?.trim() || '-',
  needs:              body.needs?.trim() || '-',
  value_propositions: body.value_propositions?.trim() || '-',
  channels:           body.channels?.trim() || '-',
  target_audience:    body.target_audience?.trim() || '-',
  kpis:               body.kpis?.trim() || '-',
  strategic_context:  body.strategic_context?.trim() || '-',
  budget_indication:  body.budget_indication?.trim() || '-',
  follow_up_by:       body.follow_up_by?.trim() || '-',

  // Service Details (optional)
  service_name:       body.service_name?.trim() || '-',
  service_detail:     body.service_detail?.trim() || '-',

  // Tone & PDF
  tone:               body.tone?.trim() || 'professional',
  pdf_text:           body.pdf_text || null,
};

return [{ json: cleanedInput }];

const data = $input.first().json;
const isPdf = data.input_method === 'pdf';

const systemPrompt = `You are a B2B marketing strategist specializing in the Testing, Inspection, Certification & Compliance (TICC) industry, with deep knowledge of Normec's services.

Your task is to extract and structure campaign data from the input provided.

Rules:
- Return ONLY valid JSON, no explanation, no markdown, no backticks
- Be specific and actionable, not generic
- Keep the same language as the input
- IMPORTANT: If a field is marked as NOT PROVIDED, return an empty string "" for that field — do NOT infer or fill it from other data
- IMPORTANT: Use exact field names as shown in the JSON template — do NOT rename or modify field names
- tone options: professional | urgent | educational`;

const userPrompt = isPdf ? `
Extract and structure campaign data from this BMC PDF document. Return ONLY this JSON:

{
  "entity": "<entity name from document>",
  "date": "<date from document, if not found return empty string>",
  "contact_person": "<contact person from document, if not found return empty string>",
  "completed_by": "<completed by from document, if not found return empty string>",
  "key_activities": "<key activities extracted from the PDF>",
  "needs": "<customer needs extracted from the PDF>",
  "value_propositions": "<value propositions extracted from the PDF>",
  "channels": "<channels extracted from the PDF>",
  "target_audience": "<specific target audience extracted from the PDF>",
  "kpis": "<KPIs extracted from the PDF>",
  "strategic_context": "<strategic context extracted from the PDF>",
  "budget_indication": "<budget indication extracted from the PDF>",
  "follow_up_by": "<follow-up by extracted from the PDF>",
  "key_problem": "<the main problem this service solves, extracted from the PDF>",
  "value_proposition": "<sharp single value proposition extracted from the PDF>",
  "key_differentiators": ["<differentiator 1>", "<differentiator 2>", "<differentiator 3>"],
  "budget": "<budget indication from the PDF>",
  "geographic_focus": "<target geography from the PDF>",
  "tone": "${data.tone || 'professional'}",
  "campaign_language": "<en or id based on document language>",
  "service_name": "<exact service name from Service Details section below — if NOT PROVIDED return empty string>",
  "service_detail": "<exact service detail from Service Details section below — if NOT PROVIDED return empty string>"
}

--- BMC PDF CONTENT ---
${data.pdf_text}

--- SERVICE DETAILS (manually provided by user) ---
Service Name: ${data.service_name && data.service_name !== '-' ? data.service_name : 'NOT PROVIDED'}
Service Detail: ${data.service_detail && data.service_detail !== '-' ? data.service_detail : 'NOT PROVIDED'}
` : `
Extract and structure campaign data from the BMC below. Return ONLY this JSON:

{
  "entity": "<entity name>",
  "target_audience": "<specific target audience derived from Target Audience field>",
  "key_problem": "<the main problem this service solves, derived from Needs field>",
  "value_proposition": "<sharp single value proposition from Value Propositions field>",
  "key_differentiators": ["<differentiator 1>", "<differentiator 2>", "<differentiator 3>"],
  "kpis": "<campaign KPIs>",
  "budget": "<budget indication>",
  "geographic_focus": "<target geography derived from Target Audience or Strategic Context>",
  "tone": "<tone of communication>",
  "campaign_language": "<en or id based on input language>",
  "service_name": "<exact service name from Service Details section below — if NOT PROVIDED return empty string>",
  "service_detail": "<exact service detail from Service Details section below — if NOT PROVIDED return empty string>"
}

--- BMC INPUT ---
Entity: ${data.entity || '-'}
Date: ${data.date || '-'}
Contact Person: ${data.contact_person || '-'}
Completed By: ${data.completed_by || '-'}
Key Activities: ${data.key_activities || '-'}
Needs: ${data.needs || '-'}
Value Propositions: ${data.value_propositions || '-'}
Channels: ${data.channels || '-'}
Target Audience: ${data.target_audience || '-'}
KPIs: ${data.kpis || '-'}
Strategic Context: ${data.strategic_context || '-'}
Budget Indication: ${data.budget_indication || '-'}
Follow-up By: ${data.follow_up_by || '-'}

--- SERVICE DETAILS (manually provided by user) ---
Service Name: ${data.service_name && data.service_name !== '-' ? data.service_name : 'NOT PROVIDED'}
Service Detail: ${data.service_detail && data.service_detail !== '-' ? data.service_detail : 'NOT PROVIDED'}

--- CAMPAIGN TONE ---
Tone: ${data.tone || 'professional'}
`;

return [{ json: { systemPrompt, userPrompt, ...data } }];

const rawText = $input.first().json.choices?.[0]?.message?.content || '';
let extracted;
try {
  const cleaned = rawText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  extracted = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Gagal parsing hasil ekstraksi LLM: ${rawText}`);
}

const isPdf = $input.first().json.input_method === 'pdf';

const requiredAlways = [
  'entity',
  'target_audience',
  'key_problem',
  'value_proposition',
  'tone',
  'campaign_language'
];

const requiredPdfOnly = [
  'key_activities',
  'needs',
  'value_propositions',
  'channels',
  'strategic_context',
  'budget_indication',
  'follow_up_by'
];

const requiredFields = isPdf
  ? [...requiredAlways, ...requiredPdfOnly]
  : requiredAlways;

for (const field of requiredFields) {
  if (!extracted[field] || (Array.isArray(extracted[field]) && extracted[field].length === 0)) {
    throw new Error(`Field '${field}' tidak ditemukan dalam hasil ekstraksi`);
  }
}

// Optional fields — fallback
extracted.service_name = extracted.service_name || '';
extracted.service_detail = extracted.service_detail || '';
extracted.kpis = extracted.kpis || extracted['kpi'] || extracted['KPIs'] || extracted["KPI's"] || '-';
extracted.budget = extracted.budget || extracted['budget_indication'] || '-';
extracted.geographic_focus = extracted.geographic_focus || extracted['target_geography'] || '-';
extracted.key_differentiators = extracted.key_differentiators || extracted['differentiators'] || extracted['key_differentiator'] || [];

return [{ json: { extracted, input_method: $input.first().json.input_method } }];

const { extracted } = $input.first().json;

if (!extracted) {
  throw new Error(`extracted is undefined — input received: ${JSON.stringify($input.first().json)}`);
}

const lang = extracted.campaign_language === 'id' ? 'Bahasa Indonesia' : 'English';

const systemPrompt = `You are a senior B2B copywriter for Normec, a Testing, Inspection, Certification & Compliance (TICC) organisation. Generate campaign content that is specific, actionable, and tailored. Return ONLY valid JSON, no explanation, no markdown, no backticks. Write in ${lang}. Tone: ${extracted.tone}.`;

const userPrompt = `Generate a B2B campaign package. Return ONLY this JSON:

{
  "landing_page": {
    "headline": "<8-12 word headline addressing the key problem>",
    "subheadline": "<1-2 sentence subheadline expanding on the value proposition>",
    "body_copy": "<3 paragraphs: problem, solution, proof + CTA>",
    "cta_text": "<CTA button text, max 6 words>"
  },
  "linkedin": {
    "phase_1": {
      "label": "Phase 1 · Awareness",
      "hook": "<attention-grabbing statement about the problem>",
      "body": "<2-3 sentences educating the audience>",
      "cta": "<soft CTA: read/learn/discover>",
      "color": "#4f6ef7"
    },
    "phase_2": {
      "label": "Phase 2 · Consideration",
      "hook": "<transition from problem to solution>",
      "body": "<2-3 sentences introducing Normec service>",
      "cta": "<medium CTA: download/watch/see>",
      "color": "#8b5cf6"
    },
    "phase_3": {
      "label": "Phase 3 · Conversion",
      "hook": "<urgency or social proof statement>",
      "body": "<2-3 sentences with proof points and urgency>",
      "cta": "<strong CTA: book/schedule/get started>",
      "color": "#22c55e"
    }
  },
  "email": {
    "subject_line": "<subject line, max 50 characters>",
    "preview_text": "<preview text, max 90 characters>",
    "body": "<full email: greeting, pain point, solution, proof points, CTA>",
    "cta_text": "<CTA button text, max 5 words>"
  }
}

--- CAMPAIGN DATA ---
Entity: ${extracted.entity}
Service: ${extracted.service_name || '-'}${extracted.service_detail ? ' — ' + extracted.service_detail : ''}
Target Audience: ${extracted.target_audience}
Geographic Focus: ${extracted.geographic_focus || '-'}
Key Problem: ${extracted.key_problem}
Value Proposition: ${extracted.value_proposition}
Key Differentiators: ${Array.isArray(extracted.key_differentiators) ? extracted.key_differentiators.join(', ') : (extracted.key_differentiators || '-')}
KPIs: ${extracted.kpis || '-'}
Budget: ${extracted.budget || '-'}
Tone: ${extracted.tone}`;

return [{ json: { systemPrompt, userPrompt, extracted } }];

const rawText = $input.first().json.choices?.[0]?.message?.content || '';
const extracted = $node["Build Campaign Prompt"].json.extracted;

let campaign;
try {
  const cleaned = rawText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  campaign = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Gagal parsing hasil campaign LLM: ${rawText}`);
}

if (!campaign.landing_page || !campaign.linkedin || !campaign.email) {
  throw new Error('Output LLM tidak lengkap — missing landing_page, linkedin, atau email');
}

return [{ json: { campaign, extracted } }];

const { campaign, extracted } = $input.first().json;

// Safety: pastikan semua field string
const lpHeadline = campaign.landing_page?.headline || '';
const lpBodyCopy = campaign.landing_page?.body_copy || '';
const emailSubject = campaign.email?.subject_line || '';
const emailBody = typeof campaign.email?.body === 'string' 
  ? campaign.email.body 
  : JSON.stringify(campaign.email?.body || '');

let score = 100;
const issues = [];
const suggestions = [];

if (lpHeadline.split(' ').length < 6) {
  score -= 10;
  issues.push('Headline terlalu pendek');
  suggestions.push('Tambahkan benefit spesifik di headline');
}

if (!lpBodyCopy.includes('?') && !lpBodyCopy.includes('!')) {
  score -= 5;
  suggestions.push('Pertimbangkan menambahkan pertanyaan rhetorical di body copy');
}

const phases = Object.values(campaign.linkedin || {});
if (phases.some(p => !p.cta || p.cta.trim() === '')) {
  score -= 15;
  issues.push('Satu atau lebih LinkedIn phase tidak memiliki CTA');
}

if (emailSubject.length > 60) {
  score -= 10;
  issues.push('Subject line terlalu panjang (>60 karakter)');
  suggestions.push('Pangkas subject line agar lebih impactful');
}

if (!emailBody.toLowerCase().includes('[first name]') &&
    !emailBody.toLowerCase().includes('hi ') &&
    !emailBody.toLowerCase().includes('dear ')) {
  score -= 5;
  suggestions.push('Tambahkan personalisasi di email greeting');
}

const allText = JSON.stringify(campaign).toLowerCase();
const hasSocialProof = ['%', 'clients', 'companies', 'manufacturers', 'certified', 'years'].some(w => allText.includes(w));
if (!hasSocialProof) {
  score -= 5;
  suggestions.push('Tambahkan social proof: angka, jumlah klien, atau testimonial');
}

const qualityCheck = {
  score: Math.max(score, 0),
  status: score >= 80 ? 'good' : score >= 60 ? 'needs_improvement' : 'poor',
  issues,
  suggestions
};

return [{ json: { campaign, extracted, qualityCheck } }];

// ─────────────────────────────────────────
// NODE: Build Final Response
// ─────────────────────────────────────────

const { campaign, extracted, qualityCheck } = $input.first().json;

const response = {
  success: true,
  extracted,
  campaign,
  qualityCheck,
  meta: {
    generated_at: new Date().toISOString(),
    model: 'llama-3.3-70b-versatile',
    provider: 'groq',
    version: '1.0.0'
  }
};

return [{ json: response }];

const data = $input.first().json;

const groqBody = JSON.stringify({
  model: "llama-3.1-8b-instant",
  messages: [
    { role: "system", content: data.systemPrompt },
    { role: "user", content: data.userPrompt }
  ],
  max_tokens: 6000,
  temperature: 0.3
});

return [{ 
  json: { 
    groqBody,
    systemPrompt: data.systemPrompt,
    userPrompt: data.userPrompt,
    input_method: data.input_method  // ← tambah ini
  } 
}];

const data = $input.first().json;

const groqBody = JSON.stringify({
  model: "llama-3.3-70b-versatile",
  messages: [
    { role: "system", content: data.systemPrompt },
    { role: "user", content: data.userPrompt }
  ],
  max_tokens: 4096,
  temperature: 0.3
});

return [{ 
  json: { 
    groqBody,
    systemPrompt: data.systemPrompt,
    userPrompt: data.userPrompt,
    extracted: data.extracted
  } 
}];
